it('should deliver notifications in order when events are emitted sequentially', async () => {
  const orderCreatedEvent: OrderCreatedEvent = {
    type: 'order:created',
    order: {
      id: 'order-1',
      userId: 'user-1',
      items: [
        { productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 },
      ],
      total: 10,
      status: 'pending',
      createdAt: new Date(),
      updatedAt: new Date(),
    },
    user: {
      id: 'user-1',
      name: 'Alice',
      email: 'alice@example.com',
      role: 'member',
      createdAt: new Date(),
      updatedAt: new Date(),
    },
    timestamp: new Date(),
  };

  const statusChangedEvent: OrderStatusChangedEvent = {
    type: 'order:status-changed',
    order: {
      id: 'order-1',
      userId: 'user-1',
      items: [],
      total: 10,
      status: 'confirmed',
      createdAt: new Date(),
      updatedAt: new Date(),
    },
    previousStatus: 'pending',
    newStatus: 'confirmed',
    timestamp: new Date(),
  };

  // Emit both events sequentially — order:created first, then status change
  await eventBus.emit(orderCreatedEvent);
  await eventBus.emit(statusChangedEvent);

  const sentEmails = emailAdapter.getSentEmails();
  expect(sentEmails).toHaveLength(2);
  // "Order Confirmation" must arrive before "Order Update"
  expect(sentEmails[0]?.email.subject).toContain('Order Confirmation');
  expect(sentEmails[1]?.email.subject).toContain('Order Update');
});

